firmware_template.source:
#include "audio_intercom.h"
#include <driver/i2s.h>
#include <math.h>
#include <string.h>

#define MIC_WS   4
#define MIC_SCK  5
#define MIC_SD   7
#define SPK_WS   15
#define SPK_BCK  16
#define SPK_DOUT 17
#define SR       16000
#define DMA_LEN  256

static int g_shift = 11;
static float g_vol = 1.0f;
static bool g_muted = false;
static int32_t g_hpf_in = 0, g_hpf_out = 0;

static int16_t process(int32_t raw) {
    int32_t v = raw >> g_shift;
    if (v > 30000) v = 30000;
    if (v < -30000) v = -30000;
    int32_t s = (int16_t)v;
    int32_t d = s - g_hpf_in;
    int32_t o = (g_hpf_out * 31785 + d * 31785) >> 15;
    if (o > 32767) o = 32767;
    if (o < -32768) o = -32768;
    g_hpf_in = s; g_hpf_out = o;
    return (int16_t)o;
}

void intercom_setup() {
    i2s_config_t mc = {};
    mc.mode = (i2s_mode_t)(I2S_MODE_MASTER | I2S_MODE_RX);
    mc.sample_rate = SR;
    mc.bits_per_sample = I2S_BITS_PER_SAMPLE_32BIT;
    mc.channel_format = I2S_CHANNEL_FMT_ONLY_LEFT;
    mc.communication_format = I2S_COMM_FORMAT_STAND_I2S;
    mc.dma_buf_count = 8;
    mc.dma_buf_len = DMA_LEN;
    mc.use_apll = true;
    i2s_driver_install(I2S_NUM_0, &mc, 0, NULL);
    i2s_pin_config_t mp = { .bck_io_num=MIC_SCK, .ws_io_num=MIC_WS, .data_out_num=-1, .data_in_num=MIC_SD };
    i2s_set_pin(I2S_NUM_0, &mp);

    i2s_config_t sc = {};
    sc.mode = (i2s_mode_t)(I2S_MODE_MASTER | I2S_MODE_TX);
    sc.sample_rate = SR;
    sc.bits_per_sample = I2S_BITS_PER_SAMPLE_16BIT;
    sc.channel_format = I2S_CHANNEL_FMT_ONLY_LEFT;
    sc.communication_format = I2S_COMM_FORMAT_STAND_I2S;
    sc.dma_buf_count = 8;
    sc.dma_buf_len = DMA_LEN;
    sc.tx_desc_auto_clear = true;
    i2s_driver_install(I2S_NUM_1, &sc, 0, NULL);
    i2s_pin_config_t sp = { .bck_io_num=SPK_BCK, .ws_io_num=SPK_WS, .data_out_num=SPK_DOUT, .data_in_num=-1 };
    i2s_set_pin(I2S_NUM_1, &sp);
    Serial.println("[intercom] ready");
}

void intercom_loop() {
    int32_t raw[DMA_LEN];
    int16_t pcm[DMA_LEN];
    size_t br = 0;
    i2s_read(I2S_NUM_0, raw, DMA_LEN * 4, &br, portMAX_DELAY);
    int n = br / 4;
    if (g_muted) { memset(pcm, 0, n * 2); }
    else {
        for (int i = 0; i < n; i++) {
            int32_t s = (int32_t)(process(raw[i]) * g_vol);
            if (s > 32767) s = 32767; if (s < -32768) s = -32768;
            pcm[i] = (int16_t)s;
        }
    }
    size_t w = 0;
    i2s_write(I2S_NUM_1, pcm, n * 2, &w, portMAX_DELAY);
}

void intercom_set_gain(int s) { if (s >= 10 && s <= 18) g_shift = s; }
void intercom_set_volume(int p) { g_vol = (float)(p < 0 ? 0 : (p > 200 ? 200 : p)) / 100.0f; }
void intercom_mute(bool m) { g_muted = m; }
